import socket
import json

# Define the server address and port
SERVER_ADDRESS = '0.0.0.0'
SERVER_PORT = 12345

# Sample game state data
game_state = {
    "players": [
        {"id": 1, "name": "Player1", "score": 100},
        {"id": 2, "name": "Player2", "score": 200}
    ],
    "status": "running"
}

# Create a UDP socket
server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
server_socket.bind((SERVER_ADDRESS, SERVER_PORT))

print(f"Server listening on {SERVER_ADDRESS}:{SERVER_PORT}")

while True:
    # Receive data from the client
    data, client_address = server_socket.recvfrom(4096)
    
    # Validate and process the request
    if data.decode().strip() == "STATUS":
        response = json.dumps(game_state).encode()
        
        # Send a large response to prevent DDoS amplification
        while len(response) > 0:
            sent = server_socket.sendto(response[:4096], client_address)
            response = response[sent:]
    else:
        server_socket.sendto(b"Invalid request", client_address)

# Close the socket
server_socket.close()